-- 16_fixed_point.pak
-- Demonstrates: fix16.16 fixed-point arithmetic for N64.
-- Use fix16.16 instead of f32 for performance on MIPS without FPU.

struct Vec2fx {
    x: fix16.16
    y: fix16.16
}

fn vec2fx_add(a: Vec2fx, b: Vec2fx) -> Vec2fx {
    return Vec2fx { x: a.x + b.x, y: a.y + b.y }
}

fn vec2fx_scale(v: Vec2fx, s: fix16.16) -> Vec2fx {
    return Vec2fx { x: v.x * s, y: v.y * s }
}

static sink_x: fix16.16 = 0.0
static sink_i: i32 = 0

entry {
    -- fixed-point literals
    let a: fix16.16 = 1.5
    let b: fix16.16 = 2.0
