struct Timer {
    elapsed: fix16.16
    limit: fix16.16
    fired: bool
}

impl Timer {
    fn init(self: *Timer, limit: fix16.16) {
        self.elapsed = 0.0
        self.limit = limit
        self.fired = false
    }

    fn update(self: *Timer, dt: fix16.16) {
        if self.fired { return }
        self.elapsed += dt
        if self.elapsed >= self.limit {
            self.fired = true
        }
    }

    fn reset(self: *Timer) {
        self.elapsed = 0.0
        self.fired = false
    }
}

