    rdpq.set_mode_fill(COLOR_BULLET)
    for i in 0..MAX_BULLETS {
        if not gs.bullets[i].active { continue }
        rdpq.fill_rectangle(gs.bullets[i].x, gs.bullets[i].y, gs.bullets[i].x + BULLET_SIZE, gs.bullets[i].y + BULLET_SIZE)
    }

