    rdpq.set_mode_fill(COLOR_ENEMY)
    for i in 0..MAX_ENEMIES {
        if not gs.enemies[i].active { continue }
        rdpq.fill_rectangle(gs.enemies[i].x, gs.enemies[i].y, gs.enemies[i].x + ENEMY_SIZE, gs.enemies[i].y + ENEMY_SIZE)
    }

    rdpq.detach_show()
}

