-- snake.pak
-- Classic Snake game: growing snake, food pickup, game over on self-collision.
-- Demonstrates: arrays as grid, enum direction, game state, wrapping movement.

use n64.display
use n64.controller
use n64.rdpq
use n64.timer

const SCREEN_W: i32 = 320
const SCREEN_H: i32 = 240
const TILE_SIZE: i32 = 8
const GRID_W: i32 = 40
const GRID_H: i32 = 30
const MAX_SNAKE: i32 = 256
const MOVE_DELAY: i32 = 6

const COLOR_BG: u32 = 0x1A1A2EFF
const COLOR_SNAKE: u32 = 0x00FF00FF
const COLOR_FOOD: u32 = 0xFF0000FF
const COLOR_HEAD: u32 = 0x00FF88FF

enum Direction: u8 {
    up
    down
    left
    right
}

struct Pos {
    x: i32
    y: i32
}

struct Snake {
    body: [256]Pos
    length: i32
    dir: Direction
}

struct Game {
    snake: Snake
    food: Pos
    score: i32
    alive: bool
    tick: i32
    seed: i32
}

fn simple_rand(gs: *Game) -> i32 {
    gs.seed = gs.seed * 1103515245 + 12345
    let val = gs.seed / 65536
    if val < 0 { return -val }
    return val
}

fn place_food(gs: *Game) {
    gs.food.x = simple_rand(gs) % GRID_W
    gs.food.y = simple_rand(gs) % GRID_H
}

fn init_game(gs: *Game) {
    gs.snake.length = 3
    gs.snake.dir = Direction.right
    gs.snake.body[0] = Pos { x: GRID_W / 2, y: GRID_H / 2 }
    gs.snake.body[1] = Pos { x: GRID_W / 2 - 1, y: GRID_H / 2 }
    gs.snake.body[2] = Pos { x: GRID_W / 2 - 2, y: GRID_H / 2 }
    gs.score = 0
    gs.alive = true
    gs.tick = 0
    gs.seed = 12345
    place_food(gs)
}

fn update(gs: *Game) {
    if not gs.alive { return }

    controller.poll()
    let pad = controller.read(0)

    -- change direction (prevent 180-degree turn)
    match gs.snake.dir {
        .up => {
