const MAX_BULLETS: i32 = 32

struct Bullet {
    x: fix16.16
    y: fix16.16
    vx: fix16.16
    vy: fix16.16
    active: bool
}

static bullets: [32]Bullet = undefined

fn init_pool() {
    for i in 0..MAX_BULLETS {
        bullets[i].active = false
    }
}

fn spawn_bullet(x: fix16.16, y: fix16.16, vx: fix16.16, vy: fix16.16) -> bool {
    for i in 0..MAX_BULLETS {
        if not bullets[i].active {
            bullets[i].x = x
            bullets[i].y = y
            bullets[i].vx = vx
            bullets[i].vy = vy
            bullets[i].active = true
            return true
        }
    }
    return false  -- pool full
}

fn update_bullets(dt: fix16.16) {
    for i in 0..MAX_BULLETS {
        if not bullets[i].active { continue }
        bullets[i].x = bullets[i].x + bullets[i].vx * dt
        bullets[i].y = bullets[i].y + bullets[i].vy * dt
        if bullets[i].y as i32 < -10 { bullets[i].active = false }
    }
}
