enum Phase: u8 {
    splash
    title
    playing
    paused
    game_over
}

struct Game {
    phase: Phase
    score: i32
    timer: f32
}

fn transition(gs: *Game, new_phase: Phase) {
    gs.phase = new_phase
    gs.timer = 0.0
}

fn update(gs: *Game, pad: joypad_status_t, dt: f32) {
    gs.timer = gs.timer + dt

    match gs.phase {
        .splash => {
            if gs.timer > 3.0 { transition(gs, Phase.title) }
        }
        .title => {
            if pad.pressed.start { transition(gs, Phase.playing) }
        }
        .playing => {
            if pad.pressed.start { transition(gs, Phase.paused) }
            -- game logic here
        }
        .paused => {
            if pad.pressed.start { transition(gs, Phase.playing) }
        }
        .game_over => {
            if pad.pressed.start { transition(gs, Phase.title) }
        }
    }
}
