struct Animation {
    frame: i32
    num_frames: i32
    timer: fix16.16
    frame_duration: fix16.16
    looping: bool
}

impl Animation {
    fn init(self: *Animation, frames: i32, speed: fix16.16, loop_anim: bool) {
        self.frame = 0
        self.num_frames = frames
        self.timer = 0.0 as fix16.16
        self.frame_duration = speed
        self.looping = loop_anim
    }

    fn update(self: *Animation, dt: fix16.16) {
        self.timer = self.timer + dt
        if self.timer >= self.frame_duration {
            self.timer = 0.0 as fix16.16
            self.frame = self.frame + 1
            if self.frame >= self.num_frames {
                if self.looping {
                    self.frame = 0
                } else {
                    self.frame = self.num_frames - 1
                }
            }
        }
    }
}
