const MAX_ENTITIES: i32 = 32

struct Entity {
    x: fix16.16
    y: fix16.16
    vx: fix16.16
    vy: fix16.16
    health: i32
    active: bool
}

static entities: [32]Entity = undefined
static entity_count: i32 = 0

fn spawn(x: fix16.16, y: fix16.16, hp: i32) -> i32 {
    for i in 0..MAX_ENTITIES {
        if not entities[i].active {
            entities[i].x = x
            entities[i].y = y
            entities[i].vx = 0.0 as fix16.16
            entities[i].vy = 0.0 as fix16.16
            entities[i].health = hp
            entities[i].active = true
            entity_count = entity_count + 1
            return i
        }
    }
    return -1
}

fn update_all(dt: fix16.16) {
    for i in 0..MAX_ENTITIES {
        if not entities[i].active { continue }
        entities[i].x = entities[i].x + entities[i].vx * dt
        entities[i].y = entities[i].y + entities[i].vy * dt
        if entities[i].health <= 0 {
            entities[i].active = false
            entity_count = entity_count - 1
        }
    }
}

fn damage(id: i32, amount: i32) {
    if id < 0 or id >= MAX_ENTITIES { return }
    if not entities[id].active { return }
    entities[id].health = entities[id].health - amount
}
