const MAX_PARTICLES: i32 = 64

struct Particle {
    x: fix16.16
    y: fix16.16
    vx: fix16.16
    vy: fix16.16
    life: i32
    active: bool
}

static particles: [64]Particle = undefined

fn init_particles() {
    for i in 0..MAX_PARTICLES {
        particles[i].active = false
    }
}

fn emit(x: fix16.16, y: fix16.16, count: i32) {
    let spawned: i32 = 0
    for i in 0..MAX_PARTICLES {
        if spawned >= count { return }
        if particles[i].active { continue }
        particles[i].x = x
        particles[i].y = y
        particles[i].vx = (rand() % 5 - 2) as fix16.16
        particles[i].vy = (-(rand() % 4) - 1) as fix16.16
        particles[i].life = 30 + rand() % 20
        particles[i].active = true
        spawned = spawned + 1
    }
}

fn update_particles() {
    for i in 0..MAX_PARTICLES {
        if not particles[i].active { continue }
        particles[i].x = particles[i].x + particles[i].vx
        particles[i].y = particles[i].y + particles[i].vy
        particles[i].vy = particles[i].vy + 0.1 as fix16.16  -- gravity
        particles[i].life = particles[i].life - 1
        if particles[i].life <= 0 {
            particles[i].active = false
        }
    }
}
