const HISTORY_SIZE: i32 = 16

struct InputHistory {
    buttons: [16]u16
    head: i32
}

impl InputHistory {
    fn init(self: *InputHistory) {
        self.head = 0
        for i in 0..HISTORY_SIZE {
            self.buttons[i] = 0
        }
    }

    fn record(self: *InputHistory, pressed: u16) {
        self.buttons[self.head] = pressed
        self.head = (self.head + 1) % HISTORY_SIZE
    }

    fn check_sequence(self: *InputHistory, seq: *u16, len: i32) -> bool {
        let start: i32 = (self.head - len + HISTORY_SIZE) % HISTORY_SIZE
        for i in 0..len {
            let idx: i32 = (start + i) % HISTORY_SIZE
            if self.buttons[idx] != seq[i] { return false }
        }
        return true
    }
}
