use n64.eeprom

-- Save data larger than 8 bytes: use multiple EEPROM blocks
-- Each block = 8 bytes. For 24 bytes, use 3 blocks.

@aligned(8)
static save_block: [8]u8 = undefined

fn save_multi(data: *u8, num_blocks: i32) {
    if not eeprom.present() { return }
    for block in 0..num_blocks {
        for i in 0..8 {
            save_block[i] = data[block * 8 + i]
        }
        eeprom.write(block, &save_block[0])
    }
}

fn load_multi(data: *u8, num_blocks: i32) {
    if not eeprom.present() { return }
    for block in 0..num_blocks {
        eeprom.read(block, &save_block[0])
        for i in 0..8 {
            data[block * 8 + i] = save_block[i]
        }
    }
}
